};

export const code = async (inputs) => {
  const disk = inputs?.disk || inputs?.item || inputs;

  const items = Array.isArray(inputs?.priceList)
    ? inputs.priceList
    : Array.isArray(inputs?.priceList?.Items)
      ? inputs.priceList.Items
      : [];

  const resourceId = disk?.id || null;
  const location = disk?.location || null;

  if (!items.length) {
    return {
      resourceId,
      location,
      dailyPricing: 0,
      currency: "USD"
    };
  }

  const diskTier = disk?.tier || null;
  const skuName = disk?.sku?.name || "";

  const redundancy = skuName?.split("_")[1];

  const expectedSkuName = `${diskTier} ${redundancy}`;
  const expectedMeterName = `${diskTier} ${redundancy} Disk`;

  const priceItem = items.find(p =>
    p.serviceName === "Storage" &&
    p.productName?.includes("Managed Disks") &&
    p.skuName === expectedSkuName &&
    p.meterName === expectedMeterName &&
    p.unitOfMeasure === "1/Month" &&
    p.type === "Consumption"
  );

  if (!priceItem || typeof priceItem.retailPrice !== "number") {
    return {
      resourceId,
      location,
      dailyPricing: 0,
      currency: "USD"
    };
  }

  const dailyPricing = priceItem.retailPrice / 30.4;
  const currency = priceItem.currencyCode || "USD";

  return {
    resourceId,
    location,
    dailyPricing,
    currency
  };
};
